import os
import base64

# Ensure directory exists
os.makedirs('luxury_salon/images', exist_ok=True)

# Minimal 1x1 gray pixel JPEG
# Header + Data for a valid JPEG file
gray_pixel_b64 = ""

# A slightly different color (lighter) for variety if needed, but for now we use gray for all
# to be safe and simple.

def create_real_jpg(filename):
    with open(os.path.join('luxury_salon/images', filename), 'wb') as f:
        f.write(base64.b64decode(gray_pixel_b64))
    print(f"Created {filename}")

# Define images to create
images = [
    'hero_bg.jpg',
    'concept.jpg',
    'gallery1.jpg',
    'gallery2.jpg',
    'gallery3.jpg',
    'gallery4.jpg',
    'gallery5.jpg',
    'gallery6.jpg',
    'map.jpg'
]

for filename in images:
    create_real_jpg(filename)
